import{c as t,Q as o,j as r,m as a}from"./chunks/framework.BXc4yaFE.js";const C=JSON.parse('{"title":"Boris Cherny 的 Claude Code 使用設定 — @bcherny","description":"","frontmatter":{"title":"Boris Cherny 的 Claude Code 使用設定 — @bcherny","author":"Boris Cherny（@bcherny）","date":"2026-01-02T00:00:00.000Z","source":"https://x.com/bcherny/status/2007179832300581177","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-01-02-@bcherny-581177.md","filePath":"research/tweets/2026-01-02-@bcherny-581177.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2026-01-02-@bcherny-581177.md"};function n(d,e,i,l,h,c){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="boris-cherny-的-claude-code-使用設定-—-bcherny" tabindex="-1">Boris Cherny 的 Claude Code 使用設定 — @bcherny <a class="header-anchor" href="#boris-cherny-的-claude-code-使用設定-—-bcherny" aria-label="Permalink to &quot;Boris Cherny 的 Claude Code 使用設定 — @bcherny&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/bcherny/status/2007179832300581177" target="_blank" rel="noreferrer">https://x.com/bcherny/status/2007179832300581177</a><strong>作者</strong>：Boris Cherny（@bcherny） <strong>發布日期</strong>：2026-01-02 <strong>收錄日期</strong>：2026-05-01 <strong>類型</strong>：推文（Note Tweet — 長文入口） <strong>統計</strong>：54496 likes · 7028 retweets · 103996 bookmarks · 8109320 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><blockquote><p><strong>⚠ 限制說明</strong>：此為 Twitter Note Tweet（<code>is_note_tweet: true</code>），fxtwitter API 僅提供入口推文文字，完整 Note 內容需登入 X.com 閱讀。以下為 API 可取得之全文。</p></blockquote><p>I&#39;m Boris and I created Claude Code. Lots of people have asked how I use Claude Code, so I wanted to show off my setup a bit.</p><p>My setup might be surprisingly vanilla! Claude Code works great out of the box, so I personally don&#39;t customize it much. There is no one correct way to use Claude Code: we intentionally build it in a way that you can use it, customize it, and hack it however you like. Each person on the Claude Code team uses it very differently.</p><p>So, here goes.</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Claude Code 創建者 Boris Cherny 公開其個人設定，核心立場是「預設值已夠好，不需要過度客製化」，對抗社群過度工程化傾向。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>「Vanilla 就是最好的設定」</strong>：Boris 作為 Claude Code 的創建者，明確表示自己的設定「surprisingly vanilla」，這是對社群「必須高度客製化才能用好 Claude Code」迷思的直接反駁。</li><li><strong>沒有唯一正確用法</strong>：「There is no one correct way to use Claude Code」是官方哲學聲明，承認每個工程師的工作方式不同，工具設計允許多樣化而非強迫一致。</li><li><strong>可客製化 ≠ 必須客製化</strong>：工具支援 hooks/skills/MCP/agents 等高度客製化，但這是能力選項而非使用前提。</li><li><strong>官方作者的示範效應</strong>：54K likes + 8.1M views 的超高傳播量，代表「作者如何用自己的產品」具有極高社群參考價值。</li><li><strong>Claude Code 團隊內部差異化</strong>：「Each person on the Claude Code team uses it very differently」揭示即便在 Anthropic 內部也無標準答案，多樣性是刻意設計的結果。</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>統計：54,496 likes · 7,028 retweets · 103,996 bookmarks · 8,109,320 views（極高傳播，CC 生態系最廣泛轉發推文之一）</li><li>作者身份：Claude Code 創建者（@bcherny, Anthropic，430K followers）</li><li>發布時間：2026-01-02（新年第一週，時機選擇強化社群關注度）</li><li>Note Tweet 格式：完整內容在 Note 內，入口推文僅 473 字元前言</li><li>來源：此推文在 <code>session-management.md</code>、<code>routines.md</code> 等 cc-workspace rules 中已多次引用為「Boris Cherny 驗證技巧」的來源</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li><strong>「Vanilla 設定」的信號價值高於技術細節</strong>：此推文最重要的資訊不是具體操作步驟，而是官方作者的立場聲明——這直接影響工程師對「是否需要大量客製化」的判斷框架。對已投入大量時間建立複雜 harness 的工程師，這是一個值得反思的訊號。</li><li><strong>完整 Note 內容不可取得</strong>：fxtwitter API 對 Note Tweets 不回傳完整 Note 內容，僅提供入口文字。Note 內可能包含具體的設定細節（如使用哪些 CLAUDE.md 規則、習慣的 slash commands 等），這些細節是真正的操作性資訊，目前無法評估。</li><li><strong>8.1M views 的 Schelling point 效應</strong>：此推文成為 Claude Code 社群的「聖經」級參考，影響了大量工程師對 Claude Code 設定的期望基準。cc-workspace 已大量引用 Boris Cherny 的後續推文，此推文是所有相關引用的起點（thread 起始）。</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>5/10</td><td>入口推文立場聲明有價值（反過度工程化），但無具體操作細節；完整 Note 未取得</td></tr><tr><td>B. 創新性 (20%)</td><td>6/10</td><td>「作者本人用 vanilla 設定」是反常識的高價值觀點，但技術新意不高</td></tr><tr><td>C. 證據品質 (20%)</td><td>8/10</td><td>第一手（作者本人）+ 超高互動數據（54K likes, 8.1M views）是最強證據；Note 完整內容未取得略扣</td></tr><tr><td>D. 技術深度 (15%)</td><td>3/10</td><td>入口推文無技術細節；深度在 Note 本文，目前無法取得</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>「不要過度工程化」原則跨所有 Claude Code 使用者，普遍適用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>5.75/10</strong></td><td>A×0.3+B×0.2+C×0.2+D×0.15+E×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Skip <strong>理由</strong>：入口推文分數未達 6，主要因完整 Note 內容無法取得，實際操作細節不明；但「不要過度客製化」的立場聲明已反映在 <code>karpathy-principles.md</code> 的 Simplicity First 原則中，無需新增整合點。若取得完整 Note 內容，建議重新評分（預估可達 7-8 分）。</p><hr>',22)])])}const g=t(s,[["render",n]]);export{C as __pageData,g as default};
